import './Toolbar.scss';

import { Checkbox } from ':components/Checkbox';
import { Divider, DividerProps } from ':components/Divider';
import { Icon } from ':components/Icon';
import { IconButton } from ':components/IconButton';
import { Menu, MenuItem } from ':components/Menu';
import { ToolbarItem } from ':components/Toolbar/ToolbarItem/ToolbarItem';
import type { ToolbarItemProps } from ':components/Toolbar/ToolbarItem/ToolbarItem.types';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useEffect, useMemo, useRef, useState } from 'react';
import type { ToolbarProps } from './Toolbar.types';

export const Toolbar: React.FC<ToolbarProps> = ({
	className,
	dataTestId = 'Toolbar',
	checkbox,
	children,
	rightIcon,
	counter,
	size = 'medium',
	enableShowMore = false,
	values,
	...rest
}) => {
	const [visibleItems, setVisibleItems] = useState([]);
	const childrenRef = useRef<HTMLDivElement>(null);
	const showMoreMenuRef = useRef(null);
	const [isShowMoreMenuOpen, setIsShowMoreMenuOpen] = useState(false);

	/**
	 * Элементы тулбара могут задаваться как через values, так и через children
	 * Приводим к одному формату в зависимости от использования values/children
	 */
	const childrenItems = useMemo(() => {
		/**
		 * Значения задаются как двумерный массив, где каждый вложенный массив - группа (разделяемая Divider-ом)
		 * Эта функция делает из двумерного массива - плоский, где группы разделены Divider-ом
		 * @param {ToolbarProps[][]} groups - Наше значение разделенное на группы
		 * @returns Возвращает ReactNode[], аналогичный тому, если бы мы задавали айтемы через children.
		 */
		const createGroupWithDividers = (groups: ToolbarItemProps[][]) => {
			return groups.reduce<React.ReactNode[]>((acc, group, index) => {
				const groupItems = group.map((itemProps, itemIndex) => (
					<ToolbarItem {...itemProps} size={size} key={`group-${index}-item-${itemIndex}`} />
				));

				if (index > 0) {
					acc.push(<Divider type="vertical" key={`divider-${index}`} />);
				}

				acc.push(...groupItems);
				return acc;
			}, []);
		};

		if (values) {
			return createGroupWithDividers(values);
		}
		/**
		 * Если айтемы задаются через children - прокидываем в каждый ToolbarItem проп size
		 */
		return React.Children.map(children, child =>
			React.isValidElement<ToolbarItemProps>(child) && child.type === ToolbarItem
				? React.cloneElement(child, { size })
				: child,
		);
	}, [values, children, size]);

	/**
	 * Функция, которая определяет какие элементы влезут, а какие мы вынесем в кнопку "еще"
	 * Добавляя каждый элемент, смотрим "влезает" ли он, если не влезает - останавливаемся на всем что ДО него
	 * Возможно, не самое оптимальное решение
	 */
	const updateItems = async () => {
		setVisibleItems([]);

		for (let i = 0; i < childrenItems?.length; i++) {
			await new Promise<void>(resolve => {
				setVisibleItems(prev => {
					const updated = [...prev, childrenItems[i]];
					resolve();
					return updated;
				});
			});
			// Проверяем "влезает ли" (ref может быть ещё null в тестах / до маунта)
			const row = childrenRef.current;
			if (row && row.scrollWidth > row.clientWidth) {
				await new Promise<void>(resolve => {
					setVisibleItems(prev => {
						const updated = prev.slice(0, -1);
						resolve();
						return updated;
					});
				});
				break;
			}
		}
		// Удаляем Divider-ы, если они остались последними
		setVisibleItems(prev => {
			const removeTrailingDividers = items => {
				let index = items.length - 1;
				while (index >= 0 && isDivider(items[index])) {
					index--;
				}
				return items.slice(0, index + 1);
			};

			return removeTrailingDividers(prev);
		});
	};

	useEffect(() => {
		updateItems();

		const handleResize = () => {
			updateItems();
		};
		// Вешаем обработчик на ресайз, что бы пересчитывать влезающие элементы при ресайзе
		window.addEventListener('resize', handleResize);
		return () => {
			window.removeEventListener('resize', handleResize);
		};
	}, [childrenItems]);

	/**
	 * @param {ReactNode} item - элемент, проверяемый на дивайдер
	 * @returns {boolean} - Является ли элемент дивайдером или нет
	 */
	const isDivider = (item: React.ReactNode): boolean => {
		return React.isValidElement<DividerProps>(item) && item.type === Divider;
	};

	/**
	 * Функция, которая рендерит содержимое меню для кнопки "еще"
	 */
	const renderMenuItems = () =>
		childrenItems
			.filter(item => !visibleItems.includes(item)) // Удаляем элементы которые уже отображены
			.filter((item, index) => !(isDivider(item) && !index)) // Удаляем первый дивайдер, если он есть
			.map((item, menuIndex) => {
				if (isDivider(item)) {
					return <Divider key={`menu-divider-${menuIndex}`} />;
				}

				if (React.isValidElement<ToolbarItemProps>(item) && item.type === ToolbarItem) {
					const { label, icon, menu, onClick } = item.props;

					return (
						<MenuItem
							key={label}
							title={label}
							iconName={icon?.iconName}
							onClick={onClick}
							children={
								menu?.items.map(
									(
										menuItem,
										menuItemIndex, // Подменю для ToolbarItem, у которых есть вложенные элементы
									) => (
										<MenuItem
											key={`menu-item-${menuItemIndex}`}
											iconName={menuItem?.iconName}
											title={menuItem.title}
											onClick={menuItem.onClick}
										/> // TODO: доработка Menu для цветных иконок
									),
								) || null
							}
						/>
					);
				}

				return null;
			});

	return (
		<div
			data-testid={dataTestId}
			role="toolbar"
			className={classNames(className, 'dsb_toolbar', `dsb_toolbar--${size}`)}
			{...rest}
		>
			{checkbox && (
				<div className={'dsb_toolbar__checkbox'}>
					<Checkbox {...checkbox} />
				</div>
			)}

			<div className={classNames('dsb_toolbar__counter', counter?.disabled && 'dsb_toolbar__counter-disabled')}>
				<Typography variant={'body3'}>{counter?.label}</Typography>
			</div>

			<div className={'dsb_toolbar__children'} ref={childrenRef} role="group" aria-controls="">
				{enableShowMore ? visibleItems : childrenItems}
				{enableShowMore && visibleItems.length !== childrenItems.length && (
					<>
						<IconButton
							size={size}
							onClick={() => setIsShowMoreMenuOpen(true)}
							ref={showMoreMenuRef}
							iconName={Icons.MoreHoriz}
							className={classNames(`dsb_toolbar__item-${size}`, 'dsb_toolbar__item', 'dsb_toolbar__item-showmore')}
						/>
						<Menu
							className="dsb_toolbar__showmore-menu"
							parent={showMoreMenuRef}
							isOpen={isShowMoreMenuOpen}
							onOutsideClick={() => setIsShowMoreMenuOpen(false)}
						>
							{renderMenuItems()}
						</Menu>
					</>
				)}
			</div>

			{rightIcon && (
				<div className={'dsb_toolbar__rightIcon'}>
					<Icon iconName={rightIcon.iconName} size={size} onClick={rightIcon.onClick} />
				</div>
			)}
		</div>
	);
};
